import{_ as a,o,c as t,ai as p}from"./chunks/framework.iE7HcrvK.js";const g=JSON.parse('{"title":"关于我","description":"","frontmatter":{"title":"关于我","prev":false,"next":false,"comment":false,"lastUpdated":false},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md"}'),r={name:"about/index.md"};function d(s,e,n,c,i,l){return o(),t("div",null,[...e[0]||(e[0]=[p('<h1 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h1><h2 id="本站历史" tabindex="-1">本站历史 <a class="header-anchor" href="#本站历史" aria-label="Permalink to &quot;本站历史&quot;">​</a></h2><p>我的第一个个人博客始建于2019年。</p><p>在此之前，我曾在CSDN和语雀上写博文和记笔记，当然实际上也没形成随手记录的习惯，记录的内容也寥寥无几，屈指可数。</p><p>在博客搭建之后，这种状况其实并没有得到改变。在2019到2023年间，我最终只留下了三十余篇博文。</p><p>在此期间，我对于博客系统投入的精力可以说远远大于这三十余篇博文本身。甚至域名都换过很多次。</p><p>曾经使用的域名有：<code>origincat.com</code>、<code>gs42.vip</code>、<code>gs42.net</code>、<code>nard.work</code>、<code>nard.im</code>、<code>duanshu.org</code>等，当然现在这些域名大多都不在我手上了。</p><p>时间回到现在，在无数次折腾博客系统本身之后，我希望把自己的精力拉回到写博客这件事上。起码将折腾博客系统的精力投入到写博客这件事上。</p><p>希望将来能有更多的内容产出。</p><h2 id="本站现状" tabindex="-1">本站现状 <a class="header-anchor" href="#本站现状" aria-label="Permalink to &quot;本站现状&quot;">​</a></h2><p><strong>关于框架：</strong></p><p>如你所见，网站目前使用的框架是<code>vitepress</code>，一个纯粹的静态网站。</p><p>在经历过<code>hexo</code>、<code>hugo</code>、<code>typecho</code>等等博客框架之后，我选择了<code>vitepress</code>这样一个文档框架。</p><p>优点很明显，网站条理清晰，当我需要查阅一个曾经使用过的工具时，非常高效。</p><p><strong>关于部署：</strong></p><p>网站目前托管在gihub pages。</p><p>可能会因为网络问题导致访问异常。</p><p><strong>关于评论：</strong></p><p>评论功能已添加，但<strong>评论功能可能随着网站变更而取消。</strong></p><p>网站原本托管在gitlab pages，为了添加评论功能迁移到github pages。</p><p>不排除再次迁移导致评论功能失效以及历史评论丢失的可能性。</p><h2 id="版权声明" tabindex="-1">版权声明 <a class="header-anchor" href="#版权声明" aria-label="Permalink to &quot;版权声明&quot;">​</a></h2><p><strong>本人保留本站所有内容的版权，禁止任何形式的转载，禁止任何形式的修改分发。</strong></p>',23)])])}const u=a(r,[["render",d]]);export{g as __pageData,u as default};
